var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......이런 곳에서 뭘 하고 있는 거지, 비숍?","JPN":"……こんなところで何をしている？　ビショップ。","ENG":"What are you doing in a place like this, Bishop?","TWN":"……妳在這種地方做什麼，大主教？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"내가 기함에서 멀리 떨어지지 말라고 했을 텐데.","JPN":"旗艦からあまり離れるなと言ったはずだ。","ENG":"I told you not to stay too far from the flagship.","TWN":"我說過不可以跑到離旗艦上太遠的地方的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"라디오...... 노래를 듣고 있다.","JPN":"ラジオ……歌を聞いている。","ENG":"I'm listening to a song from the radio...","TWN":"我在聽廣播……的歌曲。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"라디오......?","JPN":"ラジオ……？","ENG":"The radio?","TWN":"廣播……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"이 근처는 뉴 오하이오의 스텔스 필드 영향권 안이라서 외부 전파 따윈 모두 차단될 텐데?","JPN":"この辺りはニューオハイオのステルスフィールドに含まれているから、\\n外部の電波なんて一切入らないと思うが？","ENG":"We're inside the stealth field of the New Ohio and any airwaves from outside are supposed to be blocked.","TWN":"這附近都在新俄亥俄的隱形場域影響範圍內，外部電波什麼的應該都被隔斷了才對啊？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......아니, 그보다 애초에 이 이면세계 깊은 곳에서 무슨 라디오 따위가 나온다는 거지?","JPN":"……いや、それよりも、そもそもこの裏世界の奥地でラジオなんか聞けるはずがない。","ENG":"No, before that, how is that radio working in the depths of the Counterside?","TWN":"……不，還是說原來異界的深處有什麼廣播嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......여긴 스텔스 필드의 끝자락이다.","JPN":"……ここはステルスフィールドの端。","ENG":"This is the farthest end of the stealth field.","TWN":"……這裡是隱形場域的邊界。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"필드 중심부와는 달리 외부 전파가 완전히 차단되지는 않아.","JPN":"フィールド中心部とは違って、外部の電波が完全に遮断されることはない。","ENG":"Unlike in the center, there's a weak flow of radio waves here.","TWN":"和隱形場域的中心不一樣，外部電波不會被完全遮斷。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"잡음이 많긴 하지만...... 들을 정도는 되지.","JPN":"ノイズも多いが……聞けないことはない。","ENG":"It has a lot of noise to it, but it's bearable.","TWN":"雖然雜音很多……但還是能夠聽得到。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그리고 두 번째 질문에 대한 답은...... 나도 모른다.","JPN":"それから、二つ目の疑問については……私もなぜかはわからない。","ENG":"And for the second question... I have no idea.","TWN":"至於第二個問題……我也不知道。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"오래된 라디오 주파수 같은데......","JPN":"古いラジオ局の周波数みたいだが……","ENG":"It seems to be an old radio channel.","TWN":"那是很久以前的無線頻率……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"며칠 전부터 같은 노래가 계속 반복되고 있을 뿐이다.","JPN":"数日前から同じ歌が繰り返し流れている。","ENG":"It's been repeating the same song over and over again for a few days.","TWN":"從幾天前就一直在反復播放著同一首歌。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......신기하군.","JPN":"……不思議だな。","ENG":"That's weird.","TWN":"……真是不可思議呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"저 멀리 어딘가에 버려진 라디오 방송국이라도 있다는 건가?","JPN":"どこか遠くに、捨てられたラジオ局でもあるとでも？","ENG":"Could there be an abandoned radio station somewhere far from here?","TWN":"難道遠方的某處有廢棄的廣播電臺嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"하긴, 이면세계에서 이해 못할 일이 벌어지는 게 특별한 일은 아니지.","JPN":"まあ、裏世界では理解不能なことが起きてもおかしくないからな。","ENG":"Well, I guess nothing's too crazy here in the Counterside.","TWN":"不過說起來，在異界裡發生無法理解的現象，也不是什麼特別的事情就是了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그나저나 음악 감상 같은 취미가 있는 줄은 몰랐군, 비숍.","JPN":"とにかく、音楽鑑賞のような趣味があるとは知らなかったな、ビショップ。","ENG":"But I never took you for a music lover, Bishop.","TWN":"不過沒想到妳還有欣賞音樂的愛好呢，主教。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"무슨 노래를 듣고 있는 건지 궁금한데.","JPN":"どんな曲か気になるな。","ENG":"I'm actually curious what song you're listening to.","TWN":"讓人不禁好奇妳在聽什麼呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"나도 한 번 들어볼까?","JPN":"私も聞いてみていいかしら？","ENG":"Can I join you?","TWN":"我可以聽聽看嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"원한다면......","JPN":"望むなら……","ENG":"Be my guest.","TWN":"妳想聽的話……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L30_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......올드 랭 사인?","JPN":"……オールド・ラング・サイン？","ENG":"Auld Lang Syne?","TWN":"……友誼地久天長？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"이거 백 년도 더 된 노래잖아?","JPN":"これは、百年以上も昔の歌じゃないか？","ENG":"This song is more than a hundred years old!","TWN":"這不是一百多年前的歌嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"네가 이 노래를 어떻게 알고 있는 거야?","JPN":"どうしてお前がこの歌を知っている？","ENG":"How do you know this song?","TWN":"妳怎麼知道這首歌的？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"설마...... 네 모체가 좋아하던 노래였나?","JPN":"まさか……お前の母体のお気に入りだったのか？","ENG":"Was it a song that your source used to like?","TWN":"難道……是妳母體喜歡的歌嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......딱히 좋아했던 건 아니다.","JPN":"……とくにお気に入りだったわけではない。","ENG":"Not necessarily.","TWN":"……也不是特別喜歡。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"다만......","JPN":"ただ……","ENG":"But...","TWN":"只是……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"다만?","JPN":"ただ？","ENG":"But?","TWN":"只是？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"모체가 살던 지역에서 이 노래는 일반적으로 학교 졸업식 때 불리는 노래였다.","JPN":"母体が住んでいた地域でこの歌は、学校の卒業式でよく歌われていた。","ENG":"Where the source lived, this song was what they sang at the school graduation ceremony.","TWN":"在母體曾經生活的地方，學校的畢業典禮上通常都會唱這首歌。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"졸업식? 프롬 파티 같은 건가?","JPN":"卒業式？　プロムのようなものか？","ENG":"Graduation ceremony? Like a prom party?","TWN":"畢業典禮？像畢業舞會的那種？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"별로 그런 분위기의 노래는 아닌 것 같은데......","JPN":"あまりそんな雰囲気の歌ではなさそうだが……","ENG":"I don't exactly think this song has that kind of vibe.","TWN":"應該不是那種氣氛下會唱的歌啊……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그건 잘 모르겠군......","JPN":"それはよくわからない……","ENG":"I’m not sure.","TWN":"這我並不清楚……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"모체도 딱히 이 노래에 대한 특별한 추억 같은 건 없었으니까.","JPN":"母体も、この歌に特段の思い出があるわけではないから。","ENG":"The source didn't have any special memories related to the song.","TWN":"我的母體對這首歌也沒有什麼特別的回憶。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"다만 모체는...... 자신과, 자신의 지인들이 결국 학교를 졸업하지 못한 걸 아쉬워했다.","JPN":"ただ、母体は……自分や自分の友人たちが学校を卒業できなかったことを惜しんでいた。","ENG":"But... my source always felt regretful that she and her acquaintances never got to graduate from school.","TWN":"但是母體……對自己，還有自己的熟人最後都沒能畢業的事情感到很遺憾。"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그 보상심리가 계승된 것인지는 모르겠지만......","JPN":"その代償行動が私に引き継がれたのかはわからないが……","ENG":"I don't know if what I'm feeling is what remains of her past regrets,","TWN":"不知道是不是繼承了她的補償心理……"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"나도 이 노래를 듣고 있으면 어쩐지 무언가가 충족되는 느낌이......","JPN":"私もこの歌を聞いてると、何かが満たされるような気がして……","ENG":"but listening to this song, I get this strange feeling of satisfac—","TWN":"我在聽這首歌的時候，總覺得會有一種被什麼充滿的感覺……"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그만.","JPN":"やめなさい。","ENG":"That's enough.","TWN":"夠了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"바보 같은 착각은 하지 마라. 비숍 재생체.","JPN":"バカバカしい勘違いはするな、ビショップ再生体。","ENG":"Don't be absurd, Regenerated Bishop.","TWN":"別再有這種愚蠢的誤會了，大主教再生體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"넌 모체가 아니다. 애초에 인간도 아니지.","JPN":"お前は母体ではない。そもそも人間ですらない。","ENG":"You're not the source. You're not even a human.","TWN":"妳不是妳的母體。甚至從一開始就不是人類。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"졸업식 같은 건 너와 아무런 관계가 없다.","JPN":"卒業式なんて、お前とは何の関係もない。","ENG":"Graduation ceremonies have nothing to do with you.","TWN":"畢業典禮什麼的和妳一點關係也沒有。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"넌 시스템 테라사이드의 의사조정자로 만들어진 리플레이서 재생체일 뿐이다.","JPN":"お前はテラサイドシステムの意思調整者として作られたリプレイサー再生体でしかない。","ENG":"You're just a Regenerated Replacer created to serves as the Arbiter for the System Terraside.","TWN":"妳只是為了成為特拉賽德的裁決者，才被創作出來的克隆集團再生體而已。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그걸 잊지 말도록.","JPN":"くれぐれも忘れないように。","ENG":"Never forget that.","TWN":"不要忘記這一點。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그럼 어째서 우리에게 모체의 기억을 심어둔 거지?","JPN":"だったら、どうして我々に母体の記憶を植え付けた？","ENG":"Then why do we still have the memories of our sources?","TWN":"那為什麼要給我們植入母體的記憶呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"단순히 테라사이드 시스템의 부품으로 사용할 거라면 애초에 아무런 감정도 없는 기계로 만드는 게 합리적이지 않은가?","JPN":"単にテラサイドシステムの部品でしかないなら、\\nそもそも何の感情もない機械にしたほうが合理的ではないか？","ENG":"Wouldn't it be much more reasonable to turn us into mindless machines, if all you wanted was simple components of System Terraside?","TWN":"如果只是單純作為特拉賽德系統的零件，那從一開始就該製造一點感情也沒有的機械，這樣不是比較合理嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그건...... 불가피한 일이었을 뿐이다.","JPN":"それは、やむを得ないことだった。","ENG":"It was... inevitable.","TWN":"那……只是不可避免的事情而已。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"리플레이서 재생체는 단순 클론카피 같은 게 아니야.","JPN":"リプレイサー再生体は、単なるクローンではない。","ENG":"Regeneration is different from simple cloning.","TWN":"克隆集團的再生體不是單純的克隆複製體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"재생 과정에서 모체의 기억과 경험은 물론......","JPN":"再生過程で母体の記憶や経験はもちろん……","ENG":"It's a process of evolution which uses the entire cycle of the source's life and death,","TWN":"再生過程中，母體的記憶和經歷不用說……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그 죽음의 과정 전체를 기반 정보로 삼아 새로운 단계의 변이인자로 진화시키는 거다.","JPN":"その死の過程すべてをベースにして、新しいフェーズの変異因子に進化させるのだ。","ENG":"including the memories and experiences, as the base to give birth to the Mutation Factor.","TWN":"就連死亡過程都會成為基礎情報，作為新階段的變異因子。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그러니 기억 같은 핵심 요소를 삭제하면 진화된 변이인자 자체가 망가지게 된다.","JPN":"だから、記憶のようなコア要素を削除すると、進化した変異因子そのものが壊れてしまう。","ENG":"Therefore, leaving out the core components like memories can result in the breakdown of the evolved Mutation Factor itself.","TWN":"所以要是刪除記憶這種核心要素，進化的變異因子自身也會崩壞。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"피라미드의 아랫돌을 빼버리는 것과 같지.","JPN":"ピラミッドを支える最下段の石を抜くようなものだ。","ENG":"It's like taking out all the base stones from a pyramid.","TWN":"就像抽掉金字塔最底端的石塊一樣。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"더구나 네 모체는 클리포트 인자와 융합하는 바람에 그 진화의 폭이 커서,","JPN":"それに、お前の母体はクリフォト・ファクターと融合したおかげで、進化の幅が広く、","ENG":"And this process was even more extreme in your case, since your source became infused with the Qliphoth Factor.","TWN":"而且，因為妳的母體和逆卡巴拉因子融合了，所以進化的幅度更大。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그 결과물인 너의 변이인자가 구체적으로 어떤 식으로 작동하고 있는지, 현재 우리가 가진 기술로는 분석이나 재현이 불가능해.","JPN":"そのアウトプットであるお前の変異因子が具体的にどんな風に作用しているか、\\n我々の現在の技術では分析や再現ができない。","ENG":"The technology that we have isn't advanced enough to analyze or reproduce the operating mechanism of your Mutation Factor.","TWN":"因此，妳的變異因子作為這個過程的產物，具體上是以什麼方式運作的，以我們的現有技術還無法分析或再現。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그러니 기억 삭제 같은 위험한 방법을 쓸 이유가 없다.","JPN":"だからこそ、記憶削除のような危険なことをする理由がない。","ENG":"There was no reason to put your evolution at risk by deleting the source's memories.","TWN":"所以沒有使用刪除記憶這種危險方法的理由。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그런가......","JPN":"そうか……","ENG":"I see...","TWN":"是嗎……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"나는 운명 같은 건 믿지 않는 사람이지만......","JPN":"私は運命なんてものは信じないが……","ENG":"I don't believe in fate,","TWN":"雖然我不是個會相信命運什麼的人……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"어쩌면 이것이 바로 너에게 주어진 운명일지도 모르지.","JPN":"もしかしたら、これこそがお前に与えられた運命なのかもしれぬ。","ENG":"but maybe this is the fate that was given to you.","TWN":"但這說不定就是妳被賦予的命運。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......무슨 뜻이지?","JPN":"……どういう意味だ？","ENG":"What do you mean?","TWN":"……什麼意思？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"네 모체의 감정에 대해서는 나보다 네가 더 잘 알고 있겠지?","JPN":"お前の母体の気持ちについては、私よりもお前のほうが詳しかろう。","ENG":"You know much better than I do about what your source had in mind.","TWN":"關於妳母體的情感，妳應該比我更清楚吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그녀는 이 세상을 증오했고, 모든 것을 파괴하길 바랬다.","JPN":"彼女は世の中を憎しみ、すべてを破壊したがっていた。","ENG":"She loathed this world and wanted to destroy everything,","TWN":"她憎恨世上的一切，想要破壞所有事物。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그렇지 않나?","JPN":"そう思わぬか？","ENG":"didn't she?","TWN":"不是嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"얼터너티브 인자 없이 테라사이드 시스템을 기동할 수 있었던 것은 전적으로 네가 있었기 때문이다. 비숍.","JPN":"オルタナティブ・ファクターなしでテラサイドシステムを起動できたのは、\\n全面的にお前の存在のおかげだ、ビショップ。","ENG":"You were the sole reason that System Terraside was able to start without the Alternative Factor, Bishop.","TWN":"在沒有可替代因子的情況下，我們能成功啟動特拉賽德系統，全是因為有妳啊，大主教。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"클리포트 인자를 통한 돌연변이 덕분에 테라사이드 시스템의 의사조정을 맡을 정도의 연산 능력을 가지게 되었으니까.","JPN":"クリフォト・ファクターによる突然変異のおかげで、\\nテラサイドシステムの意思調整を担えるほどの演算能力を身につけられたのだから。","ENG":"The Qliphoth Factor-induced mutation equipped you with computing power sophisticated enough for the arbitration of System Terraside.","TWN":"多虧了通過逆卡巴拉因子的突變，妳才足以掌握特拉賽德系統調整意志的運算能力。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"수천, 수만의 진화방향 중에서 굳이 이러한 연산 능력을 가지게 된 것은......","JPN":"数千、数万通りもある進化の選択肢のなかで、こんな演算能力が得られたのは……","ENG":"And if you think about the fact that computation became your area of expertise among millions of other things...","TWN":"在數千、數萬計的進化方向中，偏偏就只有妳擁有了這種運算能力……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"우연치고는 공교로운 일이지.","JPN":"偶然にしてはできすぎた話だ。","ENG":"It's just too opportune to be called a coincidence.","TWN":"以偶然來說也太偶然了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"어쩌면...... 네 모체의 마지막 의지가 그런 능력을 가지도록 유도한 걸지도 몰라.","JPN":"もしかすると……お前の母体の最後の意志が、そんな能力を引き出したのかもしれぬ。","ENG":"Maybe... it was the strong will of your source that led you this way.","TWN":"說不定……妳母體最後的意志引導了妳獲得這種能力。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그러니 항상 네 모체의 증오를 기억해라, 비숍.","JPN":"だから、常にお前の母体の憎しみを覚えておくんだ、ビショップ。","ENG":"So always remember the hatred that your source had inside her.","TWN":"所以，妳要時時記住妳母體的憎恨，主教。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"테라사이드 프로젝트를 완수하는 것이야말로 그녀의 비원을 이루는 길이니까.","JPN":"テラサイドプロジェクトの完遂こそが、彼女の悲願を叶えられる道だからな。","ENG":"By completing Project Terraside, you'll be making her desperate wishes come true.","TWN":"完成特拉賽德系統才能實現她的悲願啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"이해했나?","JPN":"理解したか？","ENG":"Do you get it?","TWN":"理解了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......이해했다.","JPN":"……わかった。","ENG":"Yes.","TWN":"……理解了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그럼 돌아가지.","JPN":"なら、帰るとしよう。","ENG":"Then let's get back.","TWN":"那就走吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"조금만 더 있으면 테라사이드 프로젝트의 최종 단계다.","JPN":"もう少しでテラサイドプロジェクトの最終段階だ。","ENG":"We're not too far from the last stage of the Project Terraside.","TWN":"再過一陣子，就是特拉賽德系統的最後階段了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그때가 되면...... 너도 자유롭게 살아갈 수 있을 거야.","JPN":"その時がくれば……お前も自由に生きられるだろう。","ENG":"When all this ends, you'll be able to lead a free life.","TWN":"到那個時候……妳就可以自由自在地活著吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그때까지는...... 너 자신의 중요성을 잘 생각해서 자중하도록.","JPN":"それまでは……自分がいかに重要な存在かを考えて、慎重に行動するように。","ENG":"Until then... I want you to keep in mind how important you are to all of us.","TWN":"在那之前……請好好思考自己的重要性，並自重。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};